text:
Classifiez des descriptions de produits selon la nomenclature COICOP en utilisant le modèle hiérarchique.
viewof apiUrl = Inputs.text({
  label: "URL de l'API",
  value: "http://localhost:8000",
  width: "100%"
})
health = {
  try {
    const resp = await fetch(`${apiUrl}/health`);
    return await resp.json();
  } catch (e) {
    return { status: "unreachable", model_loaded: false };
  }
}
html`&lt;p style="margin-bottom: 1rem;"&gt;
  Statut de l'API :
  &lt;span style="
    padding: 2px 10px;
    border-radius: 12px;
    color: white;
    background: ${health.status === 'ok' ? '#2e7d32' : '#c62828'};
    font-weight: 600;
  "&gt;${health.status === 'ok' ? 'Connecté' : 'Indisponible'}&lt;/span&gt;
&lt;/p&gt;`

Prédiction

viewof product = Inputs.text({
  label: "Description du produit",
  placeholder: "pain complet bio",
  width: "100%",
  submit: "Classifier"
})







prediction = {
  if (!product || product.trim() === "") return null;
  try {
    const resp = await fetch(`${apiUrl}/predict`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ text: product, return_all_levels: true })
    });
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    return await resp.json();
  } catch (e) {
    return { error: e.message };
  }
}







html`${prediction === null
  ? html`&lt;p style="color: #888;"&gt;Saisissez une description et cliquez sur &lt;strong&gt;Classifier&lt;/strong&gt;.&lt;/p&gt;`
  : prediction.error
    ? html`&lt;p style="color: #c62828;"&gt;Erreur : ${prediction.error}&lt;/p&gt;`
    : html`
      &lt;div style="
        border: 1px solid #e0e0e0;
        border-radius: 8px;
        padding: 1.5rem;
        margin-bottom: 1rem;
        background: #fafafa;
      "&gt;
        &lt;h3 style="margin-top: 0;"&gt;Résultat&lt;/h3&gt;
        &lt;table style="width: 100%; border-collapse: collapse;"&gt;
          &lt;tr&gt;
            &lt;td style="padding: 6px 12px; font-weight: 600;"&gt;Texte&lt;/td&gt;
            &lt;td style="padding: 6px 12px;"&gt;${prediction.prediction.text}&lt;/td&gt;
          &lt;/tr&gt;
          &lt;tr&gt;
            &lt;td style="padding: 6px 12px; font-weight: 600;"&gt;Code COICOP&lt;/td&gt;
            &lt;td style="padding: 6px 12px;"&gt;
              &lt;span style="
                font-size: 1.3em;
                font-weight: 700;
                font-family: monospace;
              "&gt;${prediction.prediction.code}&lt;/span&gt;
            &lt;/td&gt;
          &lt;/tr&gt;
          &lt;tr&gt;
            &lt;td style="padding: 6px 12px; font-weight: 600;"&gt;Niveau final&lt;/td&gt;
            &lt;td style="padding: 6px 12px;"&gt;${prediction.prediction.final_level}&lt;/td&gt;
          &lt;/tr&gt;
          &lt;tr&gt;
            &lt;td style="padding: 6px 12px; font-weight: 600;"&gt;Confiance&lt;/td&gt;
            &lt;td style="padding: 6px 12px;"&gt;
              &lt;div style="display: flex; align-items: center; gap: 8px;"&gt;
                &lt;div style="
                  background: #e0e0e0;
                  border-radius: 4px;
                  width: 200px;
                  height: 16px;
                  overflow: hidden;
                "&gt;
                  &lt;div style="
                    background: ${prediction.prediction.confidence &gt; 0.7 ? '#2e7d32' : prediction.prediction.confidence &gt; 0.4 ? '#f57f17' : '#c62828'};
                    height: 100%;
                    width: ${(prediction.prediction.confidence * 100).toFixed(0)}%;
                  "&gt;&lt;/div&gt;
                &lt;/div&gt;
                &lt;span&gt;${(prediction.prediction.confidence * 100).toFixed(1)}%&lt;/span&gt;
              &lt;/div&gt;
            &lt;/td&gt;
          &lt;/tr&gt;
        &lt;/table&gt;
      &lt;/div&gt;
    `
}`







Détail par niveau

html`${
  prediction === null || prediction.error || !prediction.prediction.levels
    ? html`&lt;p style="color: #888;"&gt;Aucun détail disponible.&lt;/p&gt;`
    : html`
      &lt;table style="width: 100%; border-collapse: collapse; border: 1px solid #e0e0e0; border-radius: 8px;"&gt;
        &lt;thead&gt;
          &lt;tr style="background: #f5f5f5;"&gt;
            &lt;th style="padding: 8px 12px; text-align: left;"&gt;Niveau&lt;/th&gt;
            &lt;th style="padding: 8px 12px; text-align: left;"&gt;Code&lt;/th&gt;
            &lt;th style="padding: 8px 12px; text-align: left;"&gt;Confiance&lt;/th&gt;
          &lt;/tr&gt;
        &lt;/thead&gt;
        &lt;tbody&gt;
          ${Object.entries(prediction.prediction.levels).map(([level, data]) =&gt; html`
            &lt;tr&gt;
              &lt;td style="padding: 8px 12px; border-top: 1px solid #e0e0e0;"&gt;${level}&lt;/td&gt;
              &lt;td style="padding: 8px 12px; border-top: 1px solid #e0e0e0; font-family: monospace; font-weight: 600;"&gt;${data.code}&lt;/td&gt;
              &lt;td style="padding: 8px 12px; border-top: 1px solid #e0e0e0;"&gt;
                &lt;div style="display: flex; align-items: center; gap: 8px;"&gt;
                  &lt;div style="background: #e0e0e0; border-radius: 4px; width: 150px; height: 14px; overflow: hidden;"&gt;
                    &lt;div style="
                      background: ${data.confidence &gt; 0.7 ? '#2e7d32' : data.confidence &gt; 0.4 ? '#f57f17' : '#c62828'};
                      height: 100%;
                      width: ${(data.confidence * 100).toFixed(0)}%;
                    "&gt;&lt;/div&gt;
                  &lt;/div&gt;
                  &lt;span&gt;${(data.confidence * 100).toFixed(1)}%&lt;/span&gt;
                &lt;/div&gt;
              &lt;/td&gt;
            &lt;/tr&gt;
          `)}
        &lt;/tbody&gt;
      &lt;/table&gt;
    `
}`
